import{_ as a,o as t,c as r,ag as s}from"./chunks/framework.BuUvxvtQ.js";const p="/assets/PID.D6F7h_ys.gif",i="/assets/image-20250417213539668.Cw57_MaL.png",n="/assets/image-20250417213606526.persnse8.png",u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Other/PID控制器中的Kp、Ki和Kd参数.md","filePath":"Other/PID控制器中的Kp、Ki和Kd参数.md","lastUpdated":1775898880000}'),l={name:"Other/PID控制器中的Kp、Ki和Kd参数.md"};function d(o,e,c,h,g,_){return t(),r("div",null,[...e[0]||(e[0]=[s('<h2 id="pid控制器中的kp、ki和kd参数" tabindex="-1"><a href="https://blog.csdn.net/yunddun/article/details/107720644" target="_blank" rel="noreferrer">PID控制器中的Kp、Ki和Kd参数</a> <a class="header-anchor" href="#pid控制器中的kp、ki和kd参数" aria-label="Permalink to &quot;[PID控制器中的Kp、Ki和Kd参数](https://blog.csdn.net/yunddun/article/details/107720644)&quot;">​</a></h2><p>PID控制器是一种常见的控制算法，用于调节系统的输出，使其达到设定值。PID控制器由三个参数组成：比例（Kp）、积分（Ki）和微分（Kd）。这些参数分别对应于控制器的比例、积分和微分作用。</p><p><img src="'+p+`" alt="PID"></p><h3 id="比例-kp" tabindex="-1">比例（Kp） <a class="header-anchor" href="#比例-kp" aria-label="Permalink to &quot;比例（Kp）&quot;">​</a></h3><p>比例参数Kp决定了控制器对误差的响应速度。Kp越大，控制器对误差的反应越快，但也可能导致系统不稳定。比例控制的作用是根据当前误差调整输出，使系统迅速接近设定值。例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out_speed = Kp * err</span></span></code></pre></div><p>在这个公式中，<em>err</em>是当前误差，<em>out_speed</em>是控制器的输出速度。通过调整Kp，可以改变系统的响应速度和稳定性。</p><h3 id="积分-ki" tabindex="-1">积分（Ki） <a class="header-anchor" href="#积分-ki" aria-label="Permalink to &quot;积分（Ki）&quot;">​</a></h3><p>积分参数Ki用于消除系统的稳态误差。积分控制通过对误差进行累积，使系统在长时间内达到设定值。积分控制的作用是根据误差的累积值调整输出。例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Integral_bias += err</span></span>
<span class="line"><span></span></span>
<span class="line"><span>out_speed = Kp * err + Ki * Integral_bias</span></span></code></pre></div><p>在这个公式中，<em>Integral_bias</em>是误差的累积值。通过调整Ki，可以减小系统的稳态误差，但也可能导致系统超调<a href="https://blog.csdn.net/qq_41673920/article/details/84860697" target="_blank" rel="noreferrer">2</a>。</p><h3 id="微分-kd" tabindex="-1">微分（Kd） <a class="header-anchor" href="#微分-kd" aria-label="Permalink to &quot;微分（Kd）&quot;">​</a></h3><p>微分参数Kd用于减小系统的超调量和振荡。微分控制通过对误差的变化率进行调整，使系统更加稳定。微分控制的作用是根据误差的变化率调整输出。例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out_speed = Kp * err + Kd * (err - last_err)</span></span></code></pre></div><p>在这个公式中，<em>last_err</em>是上一次的误差。通过调整Kd，可以提高系统的稳定性和响应速度<a href="https://blog.csdn.net/yunddun/article/details/107720644" target="_blank" rel="noreferrer">1</a>。</p><h3 id="调参经验" tabindex="-1">调参经验 <a class="header-anchor" href="#调参经验" aria-label="Permalink to &quot;调参经验&quot;">​</a></h3><p>在实际应用中，调节PID参数需要一定的经验和技巧。一般来说，可以按照以下步骤进行调参：</p><p>将Ki和Kd设为0，逐步增加Kp，直到系统出现振荡，然后将Kp减小到振荡消失。增加Kd，直到系统的超调量和振荡减小。增加Ki，直到系统的稳态误差减小。</p><p>通过不断调整Kp、Ki和Kd，可以找到最优的参数组合，使系统达到最佳的控制效果<a href="https://blog.csdn.net/qq_41673920/article/details/84860697" target="_blank" rel="noreferrer">2</a>。</p><p><a href="https://blog.csdn.net/yunddun/article/details/107720644" target="_blank" rel="noreferrer">1</a>: <a href="https://blog.csdn.net/yunddun/article/details/107720644" target="_blank" rel="noreferrer">PID参数解析+调参经验笔记（经验法）</a> <a href="https://blog.csdn.net/qq_41673920/article/details/84860697" target="_blank" rel="noreferrer">2</a>: <a href="https://blog.csdn.net/qq_41673920/article/details/84860697" target="_blank" rel="noreferrer">PID算法原理 一图看懂PID的三个参数</a></p><p><a href="https://i-blog.csdnimg.cn/blog_migrate/9e966e433cc937c942410e6b0e56ddde.png" target="_blank" rel="noreferrer">https://i-blog.csdnimg.cn/blog_migrate/9e966e433cc937c942410e6b0e56ddde.png</a></p><h3 id="不同类型的pid" tabindex="-1">不同类型的PID <a class="header-anchor" href="#不同类型的pid" aria-label="Permalink to &quot;不同类型的PID&quot;">​</a></h3><p>位置式pid：计算的结果是设置值</p><p><img src="`+i+'" alt="image-20250417213539668"></p><p>增量式pid：计算的结果是设置值的改变量</p><p><img src="'+n+'" alt="image-20250417213606526"></p><p>位置式pid的Ki项是差值的累计的和，如果电机收到堵转这一项的值会持续累加导致积分饱和，致使pid算法失效，</p><p><strong>积分饱和</strong>（Integral windup）是PID控制中积分项过度积累导致控制器输出超过系统可承受的最大/最小控制范围的问题。</p><p>具体表现是：</p><ul><li>系统长时间存在较大的误差（比如设定点和测量值有较大偏差或者输出被限制），</li><li>积分项不断累积，使得PID输出值产生极大偏差，</li><li>即使误差减小，积分项仍然很大，导致控制器输出难以恢复正常，</li><li>结果造成控制系统响应变慢，甚至振荡或不稳定。</li></ul><p>arm的数学库中的pid是混合型pid没有进行积分限幅</p>',31)])])}const K=a(l,[["render",d]]);export{u as __pageData,K as default};
